sql:
SELECT COUNT(DISTINCT patient_id)
FROM patient_labs
WHERE result_status = 'Pending';

SELECT AVG(result_value) 
FROM patient_lab_results 
WHERE test_id = 1 AND result_status = 'Completed' AND result_value < 100;

SELECT lab_id, charttime, pcl, pk, plco2, pna, hct, hgb, mcv, plt, wbc, rdw, pbun, pcre, pglu, result_status, lab_technician_id, test_name
FROM patient_labs
WHERE patient_id = 0;

SELECT test_name
FROM patient_labs
WHERE result_status = 'Pending';

SELECT result_value 
FROM patient_lab_results
WHERE result_value > 75;
